import java.util.*;
import java.util.stream.*;

public class Main {

    public static void main(String[] args) {
        Scanner input = new Scanner(System.in);
        List<Integer> values = new ArrayList<>();
        while (input.hasNextInt()) values.add(input.nextInt());
        for (Iterator<Integer> iterator = values.iterator(); iterator.hasNext();) if (iterator.next() % 2 != 0) iterator.remove();
        System.out.println(values.stream().map(String::valueOf).collect(Collectors.joining(" ")));
    }
}
